#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,ax,ay,bx,by;
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d%d%d%d",&ax,&ay,&bx,&by);
        if(__gcd(abs(ax-bx),abs(ay-by))>1)
            printf("yes\n");
        else
            printf("no\n");
    }
    return 0;
}
